var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리도시 챔버. <color=#ffd34c>구 콜롬비아 폐광</color> 지하 355m.","JPN":"管理都市チェンバー。<color=#ffd34c>旧コロンビア廃鉱</color>地下355ｍ。","ENG":"Administration City Chamber. <color=#ffd34c>Abandoned Mine in Old Colombia</color>, 355m underground.","TWN":"管理局直轄市 強巴。<color=#ffd34c>舊哥倫比亞廢棄礦井</color>，地下355m。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"\\n시라사키 리프트 코퍼레이션 관할. 파이오니어 대균열 왕복 승강장 <color=#ffd34c>2-A</color>","JPN":"\\nシラサキ・リフト・コーポレーション管轄。パイオニア大亀裂往復昇降機<color=#ffd34c>2-A</color>","ENG":"\\nSirasaki Lifting Company jurisdiction. Grand Dimension Crevice Elevator, Pioneer, Platform <color=#ffd34c>2-A</color>","TWN":"\\n白崎起重株式會社所屬。大峽谷升降機，先鋒，<color=#ffd34c>2-A</color>平台"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"승강기 배치 및 점검 완료.","JPN":"昇降機の配置および点検完了。","ENG":"Elevator deployment and inspection completed.","TWN":"升降機部署及檢查完畢。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L6_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"권장 체류 시간은 24시간입니다. 그 이후로는 침식파 감염 위험이 있으니 주의하십시오.","JPN":"滞在は24時間以内が推奨されます。それを超えますと侵食派感染のリスクが発生しますのでご注意ください。","ENG":"The recommended stay time is 24 hours. After that, you will be at risk of being infected by Corruption rays.","TWN":"建議停留時間為24小時。超出24小時，將有侵蝕波感染風險，請小心。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"반갑습니다, 스펜서 씨. 토마호크 사에서 파견된 경호원 오클랜드라고 합니다.","JPN":"はじめまして、スペンサー殿。トマホーク社から派遣されましたボディーガードのオークランドと申します。","ENG":"Nice to meet you, Spencer. I'm Oakland from Tomahawk. I'll be your bodyguard for this trip.","TWN":"很高興認識你，史賓瑟女士。我叫奧克蘭，是戰斧公司派來的保鏢。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"아까 보니까 대기실에서 담배 태우던데.","JPN":"さっき待合室でタバコを吸っていたな。","ENG":"I saw you taking a smoke break back there.","TWN":"嗯，我剛才看到你在候診室抽煙。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"아… 넵.","JPN":"あ……はいっ。","ENG":"Oh... Yes.","TWN":"啊……是的。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"난 담배 냄새 싫어해. 이 아래에 있는 주민들도 마찬가지고.","JPN":"私はタバコが嫌いなんだ。この下の住人も同じくな。","ENG":"I hate the smell of cigarettes. And so do the residents down there.","TWN":"我討厭香煙的味道。住在這下面的那些傢伙也是如此。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"하하… 그럼 두고 가야죠.","JPN":"あはは……じゃあこれは置いて行きましょう。","ENG":"Haha… Then I'll leave them behind.","TWN":"哈哈……那我就得戒煙了。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"힘은 좀 쓰는 편이야?","JPN":"体力に自信はある？","ENG":"You the brawny type?","TWN":"平時做體力活嗎？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"물론이죠. 그런 일이라면 믿고 맡기세요.","JPN":"もちろんです。力仕事なら私にお任せください。","ENG":"Of course. Leave the heavy lifting to me.","TWN":"當然。體力活就交給我吧。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"이거 짐칸에 실어.","JPN":"これ、積んでおいて。","ENG":"Load this up in the back.","TWN":"把這個放到貨艙裡。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"네…? 우왓!","JPN":"……はい？　うわっ！","ENG":"Sure…? Whoa!","TWN":"什麼……？哇！"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"무겁네요. 이게 다 뭔가요?","JPN":"結構重いですね。これ何ですか？","ENG":"This is heavy. What is all this?","TWN":"好重啊。這都是些什麼？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"탐지기 부품.","JPN":"探知機の部品。","ENG":"Detector parts.","TWN":"探測器零件。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"탐지기요? 탐지기란 게 원래 이렇게 큰 겁니까?","JPN":"探知機ですか？　探知機ってこんなに大きいものだったんですね。","ENG":"Detectors? Were detectors always this big?","TWN":"探測器？探測器原來有這麼大嗎？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"뭐든 침식파가 강한 곳에서 쓰는 장비일수록 크고 무거워지는 법이니까.","JPN":"侵食派の強い場所では、その分装備のサイズも重量も大きくなるものさ。","ENG":"Anything used where the Corruption ray is strong is bulky and heavy.","TWN":"在侵蝕波越強的地區，需要使用的裝備通常越大、越重。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"강하 완료. 심도 체크 및 수트 부하 레벨 동기화 시작.","JPN":"降下完了。深度チェックおよびスーツ負荷レベルの同期化開始。","ENG":"Descent complete. Depth check and suit strain level synchronization initiated.","TWN":"下降完成。啟動深度檢查並同步防護服負荷等級。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"후우.","JPN":"ふぅ。","ENG":"Whew.","TWN":"呼。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"어어, 뭐하는 겁니까! 대균열 2층에서 수트를 벗다니!","JPN":"ちょっと、何をしているんですか！　スーツを脱ぐなんて、ここは大亀裂の2階ですよ！？","ENG":"Hey! What are you doing?! Why are you taking your suit off? We're on the 2nd floor of the Grand Dimension Crevice!","TWN":"呃，你在做什麼！為什麼要脫掉防護服！這裡可是大峽谷地下二層！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괜찮아. 하강 부하는 이미 끝났고, 이터니움 실드만 멀쩡하면 감염 위험은 없어.","JPN":"大丈夫。下降負荷も通り抜けたし、エタニウムシールドさえしっかりしていれば感染の心配はない。","ENG":"Don't sweat it. We're through the descent strain. And there's no risk of being infected as long as your Eternium shield is fine.","TWN":"沒事。下降負荷已同步，只要永恆之金盾完好，就沒有感染的風險。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"그래도 무모해요. 이런 곳에서 작은 생채기라도 났다간 침식병에 노출된다고요.","JPN":"いくらなんでも無謀です。ここでは体の一部が露出しただけでも侵食病にかかってしまうんですよ。","ENG":"This is reckless. Even a tiny scratch in a place like this could expose you to the Corruption Syndrome.","TWN":"這、這……還是有些莽撞了。在這種地方，就算暴露一點身體，也會患上侵蝕病症啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"난 갑갑하게 갇혀있는 건 죽기보다 고역이라서.","JPN":"私は窮屈な方が死ぬより嫌。","ENG":"I'd rather die than be trapped in that stuffy suit.","TWN":"對我來說，困在著這身悶熱的衣服裡比死還難受。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그리고, 경호원인 당신이 날 지켜주면 되잖아. 왜? 자신 없어?","JPN":"それにボディーガードのあなたが私を守ってくれれば問題ないでしょ？　自信ないわけ？","ENG":"Besides, I thought you were gonna protect me, Mr. Bodyguard. Feeling under the weather?","TWN":"而且，還有作為保鏢的你可以保護我。怎麼？沒有自信？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"그… 틀린 말은 아니지만 말이죠.","JPN":"まぁ……た、確かにその通りなんですが。","ENG":"Well... You're not wrong.","TWN":"那個……話是沒有錯啦。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 탐지기 설치할 테니, 거기서 망보고 있어.","JPN":"じゃあさっそく探知機を設置するから、そこで見張っておいて。","ENG":"Then I'll get the detector set up. You keep a lookout.","TWN":"那麼，我去安裝探測器，你在那裡把風。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괜히 담배 피우다 자는 녀석들 깨우지 말고.","JPN":"タバコなんか吸って、奴らを起こしたりしないように。","ENG":"Don't go off for a smoke and wake them up, all right?","TWN":"不要抽煙，免得吵醒那些正在沉睡的傢伙。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"아… 알겠습니다. 걱정 마세요.","JPN":"わ、わかりました！　ご心配なく。","ENG":"G-got it. Don't worry.","TWN":"啊……好的。你放心吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};